+unsafe fn bounded_c_string_len(ptr: *const c_char, limit: usize) -> Option<usize> {
+    if ptr.is_null() {
+        return None;
+    }
+    (0..limit).find(|&len| unsafe { *ptr.add(len) } == 0)
